/**
 * @fileType utility
 * @domain infra | pipeline
 * @pattern validation, jsdoc, zod-schema
 * @ai-summary Pipeline health monitoring utility for Cody pipeline stages
 */

import { z } from 'zod'

// =============================================================================
// Interfaces
// =============================================================================

/**
 * Represents the health status of a single pipeline stage
 * @interface HealthStatus
 */
export interface HealthStatus {
  /** Name of the pipeline stage */
  stage: string
  /** Whether the stage is currently healthy */
  healthy: boolean
  /** Human-readable status message */
  message: string
  /** ISO timestamp of when the status was checked */
  timestamp: string
}

/**
 * Represents an overall pipeline health report
 * @interface Report
 */
export interface Report {
  /** Overall health assessment ('healthy' | 'degraded' | 'unhealthy') */
  overallHealth: 'healthy' | 'degraded' | 'unhealthy'
  /** Individual stage health statuses */
  stages: HealthStatus[]
  /** ISO timestamp when the report was generated */
  generatedAt: string
  /** List of recommendations for improving pipeline health */
  recommendations: string[]
}

/**
 * Represents retry strategy recommendations for a failed stage
 * @interface RetryStrategy
 */
export interface RetryStrategy {
  /** Name of the failed stage */
  stage: string
  /** Recommended retry strategy */
  strategy: 'immediate' | 'exponential' | 'manual' | 'skip'
  /** Maximum number of retry attempts recommended */
  maxRetries: number
  /** Timeout in milliseconds before next retry */
  timeout: number
}

// =============================================================================
// Zod Schemas for Input Validation
// =============================================================================

/**
 * Schema for validating stage name input
 */
const stageNameSchema = z
  .string()
  .min(1, 'Stage name is required')
  .trim()
  .refine((val) => val.length > 0, 'Stage name cannot be empty after trimming')

/**
 * Schema for health status returned by checkStageHealth
 */
const healthStatusSchema = z.object({
  stage: z.string(),
  healthy: z.boolean(),
  message: z.string(),
  timestamp: z.string(),
})

// =============================================================================
// Default Stage Timeouts (in milliseconds)
// =============================================================================

const DEFAULT_STAGE_TIMEOUTS: Record<string, number> = {
  taskify: 60000, // 1 minute
  gap: 120000, // 2 minutes
  architect: 180000, // 3 minutes
  'plan-gap': 300000, // 5 minutes
  build: 600000, // 10 minutes
  commit: 60000, // 1 minute
  review: 120000, // 2 minutes
  verify: 300000, // 5 minutes
  pr: 60000, // 1 minute
}

const DEFAULT_TIMEOUT = 300000 // 5 minutes fallback

// =============================================================================
// Retry Strategy Recommendations per Stage
// =============================================================================

const STAGE_RETRY_STRATEGIES: Record<string, RetryStrategy> = {
  taskify: { stage: 'taskify', strategy: 'exponential', maxRetries: 3, timeout: 30000 },
  gap: { stage: 'gap', strategy: 'exponential', maxRetries: 2, timeout: 60000 },
  architect: { stage: 'architect', strategy: 'manual', maxRetries: 1, timeout: 0 },
  'plan-gap': { stage: 'plan-gap', strategy: 'manual', maxRetries: 1, timeout: 0 },
  build: { stage: 'build', strategy: 'exponential', maxRetries: 3, timeout: 120000 },
  commit: { stage: 'commit', strategy: 'immediate', maxRetries: 2, timeout: 10000 },
  review: { stage: 'review', strategy: 'manual', maxRetries: 1, timeout: 0 },
  verify: { stage: 'verify', strategy: 'exponential', maxRetries: 2, timeout: 60000 },
  pr: { stage: 'pr', strategy: 'immediate', maxRetries: 3, timeout: 10000 },
}

/**
 * Gets the default timeout for a given pipeline stage
 * @param stage - The name of the pipeline stage
 * @returns Timeout in milliseconds, defaults to 300000 (5 minutes) for unknown stages
 */
export function getStageTimeout(stage: string): number {
  return DEFAULT_STAGE_TIMEOUTS[stage] ?? DEFAULT_TIMEOUT
}

// =============================================================================
// PipelineHealthReport Class
// =============================================================================

/**
 * Monitors and reports on Cody pipeline health
 * @class PipelineHealthReport
 */
export class PipelineHealthReport {
  /**
   * Tracks which stages have been checked in the current report cycle
   */
  private checkedStages: Set<string> = new Set()

  /**
   * Stored health statuses for generating reports
   */
  private stageStatuses: Map<string, HealthStatus> = new Map()

  /**
   * Checks the health status of a specific pipeline stage
   * @param stage - The name of the stage to check
   * @returns HealthStatus object with stage health information
   * @throws Error if stage name is empty or invalid
   */
  checkStageHealth(stage: string): HealthStatus {
    // Validate input
    const validationResult = stageNameSchema.safeParse(stage)
    if (!validationResult.success) {
      throw new Error(`Invalid stage name: ${validationResult.error.issues[0]?.message ?? 'unknown error'}`)
    }

    const trimmedStage = validationResult.data

    // Determine health based on stage (in a real system, this would check actual metrics)
    const isHealthy = this.determineStageHealth(trimmedStage)
    const message = isHealthy
      ? `Stage '${trimmedStage}' is operating normally`
      : `Stage '${trimmedStage}' is experiencing issues`

    const status: HealthStatus = {
      stage: trimmedStage,
      healthy: isHealthy,
      message,
      timestamp: new Date().toISOString(),
    }

    // Store the status
    this.stageStatuses.set(trimmedStage, status)
    this.checkedStages.add(trimmedStage)

    return status
  }

  /**
   * Determines if a stage is healthy based on its name and current state
   * @param stage - The stage name
   * @returns Boolean indicating health status
   */
  private determineStageHealth(stage: string): boolean {
    // This is a simplified implementation
    // In production, this would check actual pipeline metrics, logs, etc.
    const unhealthyPatterns = ['fail', 'error', 'timeout', 'crash']
    const stageLower = stage.toLowerCase()

    return !unhealthyPatterns.some((pattern) => stageLower.includes(pattern))
  }

  /**
   * Generates an overall pipeline health report
   * @returns Report object with overall health assessment and stage details
   */
  generateReport(): Report {
    const stages = Array.from(this.stageStatuses.values())
    const generatedAt = new Date().toISOString()

    // Calculate overall health
    let overallHealth: Report['overallHealth'] = 'healthy'
    if (stages.length === 0) {
      overallHealth = 'degraded'
    } else {
      const healthyCount = stages.filter((s) => s.healthy).length
      const healthyRatio = healthyCount / stages.length

      if (healthyRatio < 0.5) {
        overallHealth = 'unhealthy'
      } else if (healthyRatio < 1) {
        overallHealth = 'degraded'
      }
    }

    // Generate recommendations
    const recommendations: string[] = []
    if (overallHealth === 'unhealthy') {
      recommendations.push('Multiple stages are failing. Consider reviewing recent changes.')
      recommendations.push('Check system logs for error patterns.')
    } else if (overallHealth === 'degraded') {
      recommendations.push('Some stages are not operating optimally.')
      recommendations.push('Monitor closely and prepare for potential issues.')
    }

    // Add per-stage recommendations
    for (const stage of stages) {
      if (!stage.healthy) {
        const retryStrategy = this.getRetryRecommendationInternal(stage.stage)
        if (retryStrategy.strategy === 'manual') {
          recommendations.push(`Stage '${stage.stage}' requires manual intervention.`)
        } else if (retryStrategy.strategy === 'exponential') {
          recommendations.push(`Stage '${stage.stage}' should be retried with exponential backoff.`)
        }
      }
    }

    return {
      overallHealth,
      stages,
      generatedAt,
      recommendations,
    }
  }

  /**
   * Internal method to get retry recommendation without validation (for use in generateReport)
   * @param failedStage - The name of the failed stage
   * @returns RetryStrategy for the given stage
   */
  private getRetryRecommendationInternal(failedStage: string): RetryStrategy {
    return (
      STAGE_RETRY_STRATEGIES[failedStage] ?? {
        stage: failedStage,
        strategy: 'exponential' as const,
        maxRetries: 2,
        timeout: getStageTimeout(failedStage),
      }
    )
  }

  /**
   * Gets retry strategy recommendation for a failed stage
   * @param failedStage - The name of the failed stage
   * @returns RetryStrategy object with retry recommendations
   * @throws Error if stage name is empty or invalid
   */
  getRetryRecommendation(failedStage: string): RetryStrategy {
    // Validate input
    const validationResult = stageNameSchema.safeParse(failedStage)
    if (!validationResult.success) {
      throw new Error(`Invalid stage name: ${validationResult.error.issues[0]?.message ?? 'unknown error'}`)
    }

    return this.getRetryRecommendationInternal(validationResult.data)
  }
}

// =============================================================================
// Exports
// =============================================================================

export { stageNameSchema, healthStatusSchema }

