import { describe, it, expect, beforeEach } from 'vitest'
import {
  PipelineHealthReport,
  getStageTimeout,
  stageNameSchema,
  healthStatusSchema,
  type HealthStatus,
  type Report,
  type RetryStrategy,
} from '@/infra/utils/pipeline-health'

describe('PipelineHealthReport', () => {
  let reporter: PipelineHealthReport

  beforeEach(() => {
    reporter = new PipelineHealthReport()
  })

  describe('instantiation', () => {
    it('should create a PipelineHealthReport instance', () => {
      expect(reporter).toBeDefined()
    })

    it('should be an instance of PipelineHealthReport', () => {
      expect(reporter).toBeInstanceOf(PipelineHealthReport)
    })
  })

  describe('checkStageHealth', () => {
    it('should return HealthStatus for a valid stage name', () => {
      const result = reporter.checkStageHealth('build')

      expect(result).toBeDefined()
      expect(result.stage).toBe('build')
      expect(typeof result.healthy).toBe('boolean')
      expect(typeof result.message).toBe('string')
      expect(typeof result.timestamp).toBe('string')
    })

    it('should return healthy status for normal stage names', () => {
      const result = reporter.checkStageHealth('build')

      expect(result.healthy).toBe(true)
      expect(result.message).toContain('is operating normally')
    })

    it('should return unhealthy status for stage names with error patterns', () => {
      const result = reporter.checkStageHealth('build-error')

      expect(result.healthy).toBe(false)
      expect(result.message).toContain('experiencing issues')
    })

    it('should trim whitespace from stage names', () => {
      const result = reporter.checkStageHealth('  build  ')

      expect(result.stage).toBe('build')
    })

    it('should throw error for empty string stage name', () => {
      expect(() => reporter.checkStageHealth('')).toThrow('Invalid stage name')
    })

    it('should throw error for whitespace-only stage name', () => {
      expect(() => reporter.checkStageHealth('   ')).toThrow('Invalid stage name')
    })

    it('should store status for later report generation', () => {
      reporter.checkStageHealth('architect')
      reporter.checkStageHealth('build')

      const report = reporter.generateReport()
      expect(report.stages.length).toBeGreaterThanOrEqual(2)
    })
  })

  describe('generateReport', () => {
    it('should return a Report with all required fields', () => {
      const report = reporter.generateReport()

      expect(report).toBeDefined()
      expect(['healthy', 'degraded', 'unhealthy']).toContain(report.overallHealth)
      expect(Array.isArray(report.stages)).toBe(true)
      expect(typeof report.generatedAt).toBe('string')
      expect(Array.isArray(report.recommendations)).toBe(true)
    })

    it('should return degraded when no stages have been checked', () => {
      const report = reporter.generateReport()

      expect(report.overallHealth).toBe('degraded')
      expect(report.stages).toHaveLength(0)
    })

    it('should return healthy when all checked stages are healthy', () => {
      reporter.checkStageHealth('build')
      reporter.checkStageHealth('commit')
      reporter.checkStageHealth('review')

      const report = reporter.generateReport()
      expect(report.overallHealth).toBe('healthy')
    })

    it('should return unhealthy when most stages are unhealthy', () => {
      reporter.checkStageHealth('build-error')
      reporter.checkStageHealth('commit-error')
      reporter.checkStageHealth('review-error')
      reporter.checkStageHealth('pr-error')

      const report = reporter.generateReport()
      expect(report.overallHealth).toBe('unhealthy')
    })

    it('should include recommendations when stages are unhealthy', () => {
      reporter.checkStageHealth('build-error')

      const report = reporter.generateReport()
      expect(report.recommendations.length).toBeGreaterThan(0)
    })

    it('should include ISO timestamp in generatedAt', () => {
      const report = reporter.generateReport()

      // Should be valid ISO date string
      expect(() => new Date(report.generatedAt)).not.toThrow()
    })
  })

  describe('getRetryRecommendation', () => {
    it('should return RetryStrategy for a valid stage name', () => {
      const result = reporter.getRetryRecommendation('build')

      expect(result).toBeDefined()
      expect(result.stage).toBe('build')
      expect(['immediate', 'exponential', 'manual', 'skip']).toContain(result.strategy)
      expect(typeof result.maxRetries).toBe('number')
      expect(typeof result.timeout).toBe('number')
    })

    it('should return exponential strategy with correct values for build stage', () => {
      const result = reporter.getRetryRecommendation('build')

      expect(result.strategy).toBe('exponential')
      expect(result.maxRetries).toBe(3)
      expect(result.timeout).toBe(120000)
    })

    it('should return manual strategy for architect stage', () => {
      const result = reporter.getRetryRecommendation('architect')

      expect(result.strategy).toBe('manual')
      expect(result.maxRetries).toBe(1)
      expect(result.timeout).toBe(0)
    })

    it('should return immediate strategy for commit stage', () => {
      const result = reporter.getRetryRecommendation('commit')

      expect(result.strategy).toBe('immediate')
      expect(result.maxRetries).toBe(2)
      expect(result.timeout).toBe(10000)
    })

    it('should return default strategy for unknown stage', () => {
      const result = reporter.getRetryRecommendation('unknown-stage')

      expect(result.stage).toBe('unknown-stage')
      expect(result.strategy).toBe('exponential')
      expect(result.maxRetries).toBe(2)
      expect(result.timeout).toBe(300000) // default timeout
    })

    it('should throw error for empty string stage name', () => {
      expect(() => reporter.getRetryRecommendation('')).toThrow('Invalid stage name')
    })

    it('should throw error for whitespace-only stage name', () => {
      expect(() => reporter.getRetryRecommendation('   ')).toThrow('Invalid stage name')
    })

    it('should trim whitespace from stage names', () => {
      const result = reporter.getRetryRecommendation('  build  ')

      expect(result.stage).toBe('build')
    })
  })

  describe('getStageTimeout', () => {
    it('should return correct timeout for known stages', () => {
      expect(getStageTimeout('taskify')).toBe(60000)
      expect(getStageTimeout('gap')).toBe(120000)
      expect(getStageTimeout('architect')).toBe(180000)
      expect(getStageTimeout('build')).toBe(600000)
      expect(getStageTimeout('commit')).toBe(60000)
      expect(getStageTimeout('review')).toBe(120000)
      expect(getStageTimeout('verify')).toBe(300000)
      expect(getStageTimeout('pr')).toBe(60000)
    })

    it('should return default timeout for unknown stages', () => {
      expect(getStageTimeout('unknown')).toBe(300000)
      expect(getStageTimeout('custom-stage')).toBe(300000)
    })

    it('should return number type for all calls', () => {
      const result = getStageTimeout('build')
      expect(typeof result).toBe('number')
    })
  })

  describe('Zod schemas', () => {
    describe('stageNameSchema', () => {
      it('should validate non-empty strings', () => {
        const result = stageNameSchema.safeParse('build')
        expect(result.success).toBe(true)
      })

      it('should reject empty strings', () => {
        const result = stageNameSchema.safeParse('')
        expect(result.success).toBe(false)
      })

      it('should reject whitespace-only strings', () => {
        const result = stageNameSchema.safeParse('   ')
        expect(result.success).toBe(false)
      })

      it('should trim and validate trimmed non-empty strings', () => {
        const result = stageNameSchema.safeParse('  build  ')
        expect(result.success).toBe(true)
        if (result.success) {
          expect(result.data).toBe('build')
        }
      })
    })

    describe('healthStatusSchema', () => {
      it('should validate valid HealthStatus object', () => {
        const status: HealthStatus = {
          stage: 'build',
          healthy: true,
          message: 'OK',
          timestamp: new Date().toISOString(),
        }
        const result = healthStatusSchema.safeParse(status)
        expect(result.success).toBe(true)
      })

      it('should reject invalid HealthStatus (missing healthy)', () => {
        const invalid = {
          stage: 'build',
          message: 'OK',
          timestamp: new Date().toISOString(),
        }
        const result = healthStatusSchema.safeParse(invalid)
        expect(result.success).toBe(false)
      })
    })
  })

  describe('integration scenarios', () => {
    it('should track multiple stage checks and generate cumulative report', () => {
      reporter.checkStageHealth('taskify')
      reporter.checkStageHealth('gap')
      reporter.checkStageHealth('architect')
      reporter.checkStageHealth('build')

      const report = reporter.generateReport()
      expect(report.stages.length).toBe(4)
      expect(report.stages.map((s) => s.stage)).toEqual([
        'taskify',
        'gap',
        'architect',
        'build',
      ])
    })

    it('should generate appropriate recommendations for mixed health', () => {
      reporter.checkStageHealth('build')
      reporter.checkStageHealth('commit-error')

      const report = reporter.generateReport()
      expect(report.overallHealth).toBe('degraded')
      expect(report.recommendations.length).toBeGreaterThan(0)
    })

    it('should handle repeated checks of the same stage', () => {
      reporter.checkStageHealth('build')
      reporter.checkStageHealth('build')
      reporter.checkStageHealth('build')

      const report = reporter.generateReport()
      // Should only have one entry per stage (last check wins)
      const buildStages = report.stages.filter((s) => s.stage === 'build')
      expect(buildStages).toHaveLength(1)
    })
  })
})

describe('getStageTimeout (standalone)', () => {
  it('should export getStageTimeout as a function', () => {
    expect(typeof getStageTimeout).toBe('function')
  })

  it('should return positive timeout values', () => {
    const stages = ['taskify', 'gap', 'architect', 'build', 'commit', 'review', 'verify', 'pr', 'unknown']
    for (const stage of stages) {
      expect(getStageTimeout(stage)).toBeGreaterThan(0)
    }
  })
})

